pub fn is_even(n: i32) -> bool {
    n % 2 == 0
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_is_even() {
        assert!(is_even(4));
        assert!(!is_even(7));
        assert_eq!(is_even(0), true);
    }

    #[test]
    fn test_is_even_negative() {
        assert!(is_even(-2));
        assert!(!is_even(-3));
    }
}
